SELECT poll_id, percentage
FROM poll_candidate_scores
WHERE candidate_id = 1;

SELECT candidate_id, AVG(percentage) AS average_support
FROM poll_candidate_scores
GROUP BY candidate_id;

SELECT change_description, change_date
FROM poll_history
WHERE poll_id = 0 AND change_type = 'update';

SELECT AVG(margin_of_error) AS avg_margin_of_error, COUNT(*) AS total_polls
FROM poll_metadata
WHERE margin_of_error IS NOT NULL;
